import { useState, useRef } from "react";
import { useNavigate } from "react-router-dom";
import { FiMail } from "react-icons/fi";
import "./styles.css";

export default function EmailVerify() {
  const navigate = useNavigate();
  const [otp, setOtp] = useState(["", "", "", "", "", ""]);
  const inputs = useRef([]);

  const handleChange = (val, i) => {
    if (!/^\d*$/.test(val)) return;

    const newOtp = [...otp];
    newOtp[i] = val.slice(-1);
    setOtp(newOtp);

    if (val && i < 5) inputs.current[i + 1].focus();
  };

  const handleVerify = () => {
    if (otp.join("") === "123456") {
      navigate("/success", { state: { type: "email" } });
    } else {
      alert("Invalid Code (use 123456)");
    }
  };

  return (
    <div className="container">
      <div className="card">
        <div className="icon-circle purple">
          <FiMail size={28} />
        </div>

        <h2>Verify Your Email</h2>

        <p className="subtext">
          We’ve sent a 6-digit code to <br />
          <span className="highlight purple-text">
            yourmail@example.com <span className="edit">Edit</span>
          </span>
        </p>

        <div className="otp-box">
          {otp.map((d, i) => (
            <input
              key={i}
              ref={(el) => (inputs.current[i] = el)}
              value={d}
              onChange={(e) => handleChange(e.target.value, i)}
              maxLength={1}
            />
          ))}
        </div>

        <p className="resend">Resend code in <span>00:45</span></p>

        <button className="purple-btn" onClick={handleVerify}>
          Verify Code
        </button>
      </div>
    </div>
  );
}
